-- USER_INVITATION_EXISTING: EMAIL sent to an existing platform user when invited to join a new organisation
INSERT INTO notifications.templates (
    name,
    channel,
    content_type,
    subject,
    body_template,
    is_active,
    created_at,
    created_by,
    variable_definitions
) VALUES (
             'USER_INVITATION_EXISTING',
             'EMAIL',
             'HTML',
             '[(${organizationName})]: You have been invited to join us on Ebikes Africa',
             '<!DOCTYPE html><html lang="en" xmlns="http://www.w3.org/1999/xhtml"><head><meta content="text/html; charset=UTF-8" http-equiv="Content-Type"><meta content="width=device-width,initial-scale=1" name="viewport"><meta content="" name="x-apple-disable-message-reformatting"><title>You have been invited</title><style>@media only screen and (max-width:600px){.container{width:100%!important}.mobile-padding{padding-left:20px!important;padding-right:20px!important}}body{margin:0;padding:0;background-color:#f5f5f5}table{border-collapse:collapse}img{border:0;display:block}a{color:#2d7a3e}</style></head><body style="margin:0;padding:0;background-color:#f5f5f5;font-family:Poppins,Arial,sans-serif;-webkit-text-size-adjust:100%;-ms-text-size-adjust:100%"><div style="display:none;font-size:1px;line-height:1px;max-height:0;max-width:0;opacity:0;overflow:hidden">[[${inviterName}]] has invited you to join [[${organizationName}]] on Ebikes Africa. Expires in [[${expirationTime}]].</div><table border="0" cellpadding="0" cellspacing="0" role="presentation" style="width:100%;margin:0;padding:0;background-color:#f5f5f5;border-collapse:collapse" width="100%"><tr><td align="center" style="padding:40px 0"><table border="0" cellpadding="0" cellspacing="0" role="presentation" style="background-color:#fff;width:100%;max-width:600px;margin:0 auto;border-collapse:collapse" width="600" class="container"><tr><td align="center" style="padding:40px 30px;background-color:#2d7a3e"><img th:alt="${organizationName}" alt="" height="40" th:src="${logoUrl}" src="" style="display:block;border:0;height:40px;width:40px;margin:0 auto" width="40"></td></tr><tr><td style="padding:48px 60px;font-family:Poppins,Arial,sans-serif;font-size:16px;line-height:24px;color:#4a4a4a" class="mobile-padding"><h1 style="margin:0 0 24px 0;font-family:Poppins,Arial,sans-serif;font-size:28px;line-height:36px;color:#1a1a1a;font-weight:600">You Have Been Invited</h1><p style="margin:0 0 16px 0;font-family:Poppins,Arial,sans-serif;font-size:16px;line-height:24px;color:#4a4a4a">Hi <strong style="font-weight:600">[[${username}]]</strong>,</p><p style="margin:0 0 24px 0;font-family:Poppins,Arial,sans-serif;font-size:16px;line-height:24px;color:#4a4a4a"><strong style="font-weight:600">[[${inviterName}]]</strong> has invited you to join <strong style="font-weight:600">[[${organizationName}]]</strong> on Ebikes Africa. As you already have an account, simply accept the invitation below to get started.</p><table border="0" cellpadding="0" cellspacing="0" role="presentation" style="width:100%;margin:0 0 24px 0;border-collapse:collapse" width="100%"><tr><td align="center" style="padding:0"><table border="0" cellpadding="0" cellspacing="0" role="presentation" style="border-collapse:collapse"><tr><td align="center" style="border-radius:6px;background-color:#2d7a3e"><a th:href="${acceptLink}" href="#" style="display:inline-block;padding:14px 32px;font-family:Poppins,Arial,sans-serif;font-size:16px;font-weight:600;color:#fff;text-decoration:none;background-color:#2d7a3e;border-radius:6px;text-align:center;line-height:20px" target="_blank">Accept Invitation</a></td></tr></table></td></tr></table><table border="0" cellpadding="0" cellspacing="0" role="presentation" style="width:100%;background-color:#f9f9f9;border-left:4px solid #2d7a3e;margin:0 0 24px 0;border-collapse:collapse" width="100%"><tr><td style="padding:16px 20px;font-family:Poppins,Arial,sans-serif;font-size:14px;line-height:20px;color:#4a4a4a"><strong style="font-weight:600">This invitation will expire in [[${expirationTime}]].</strong> Please accept it before it expires.</td></tr></table><p style="margin:0;font-family:Poppins,Arial,sans-serif;font-size:14px;line-height:20px;color:#6b6b6b">If you were not expecting this invitation, you can safely ignore this email. Your existing account will not be affected.</p></td></tr><tr><td style="padding:32px 60px;background-color:#f9f9f9;border-top:1px solid #e5e5e5;font-family:Poppins,Arial,sans-serif;text-align:center" class="mobile-padding"><p style="margin:0 0 16px 0;font-family:Poppins,Arial,sans-serif;font-size:14px;line-height:20px;color:#6b6b6b;text-align:center"><strong style="color:#4a4a4a;font-weight:600">[[${organizationName}]]</strong><br><span style="color:#6b6b6b">[[${organizationAddress}]]</span></p><p style="margin:0 0 16px 0;font-family:Poppins,Arial,sans-serif;font-size:14px;line-height:20px;color:#6b6b6b;text-align:center">Need help? <a th:href="${supportUrl}" href="#" style="color:#2d7a3e;text-decoration:underline" target="_blank">Contact Support</a></p><p style="margin:0;font-family:Poppins,Arial,sans-serif;font-size:12px;line-height:18px;color:#999;text-align:center">This is an automated message, please do not reply to this email.<br>© [[${currentYear}]] [[${organizationName}]]. All rights reserved.</p></td></tr></table></td></tr></table></body></html>',
             true,
             NOW(),
             'system:liquibase-seed',
             '[
               {"name":"username","type":"STRING","description":"Display name of the existing user receiving the invitation","required":true,"sensitive":false},
               {"name":"inviterName","type":"STRING","description":"Display name of the person who sent the invitation","required":true,"sensitive":false},
               {"name":"acceptLink","type":"STRING","description":"Token-bearing acceptance URL scoped to the inviting organisation. Rendered unescaped — must only ever be populated from internal token generation, never from user input","required":true,"sensitive":true},
               {"name":"expirationTime","type":"STRING","description":"Human-readable expiry duration for the invitation link, e.g. 48 hours","required":true,"sensitive":false},
               {"name":"logoUrl","type":"STRING","description":"Publicly accessible URL for the organisation logo image","required":false,"sensitive":false},
               {"name":"organizationName","type":"STRING","description":"Display name of the organisation sending the notification","required":false,"sensitive":false},
               {"name":"organizationAddress","type":"STRING","description":"Physical or postal address of the organisation","required":false,"sensitive":false},
               {"name":"supportUrl","type":"STRING","description":"Publicly accessible URL to the organisation support page","required":false,"sensitive":false},
               {"name":"currentYear","type":"STRING","description":"Current calendar year used in the copyright notice","required":false,"sensitive":false}
             ]'
         );

--rollback DELETE FROM notifications.templates WHERE name = 'USER_INVITATION_EXISTING';